mapper.select:
select p.*, s.name as shopName, c.name as categoryName
from product p
left join shop s on p.shop_id = s.id
left join category c on p.category_id = c.id


        and p.shop_id = #{shopId}


        and p.category_id = #{categoryId}


        and p.name like concat('%', #{name}, '%')


        and p.price = #{price}


        and p.stock = #{stock}


        and p.description like concat('%', #{description}, '%')


        and p.sales = #{sales}


        and p.status = #{status}


        and p.create_time = #{createTime}


        and p.update_time = #{updateTime}


order by p.id desc
